
.history-layout {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.section-head {
  font-family: var(--font-headline);
  font-size: 0.85rem;
  font-weight: bold;
  border-bottom: 2px solid var(--c-ink);
  padding-bottom: 2px;
  margin-bottom: 6px;
  letter-spacing: 0.05em;
}

/* 默认历史航道节点 */
.railway-nodes {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
}

.railway-node {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 4px 8px;
  border: 1.5px solid;
  font-family: var(--font-body);
  font-size: 0.75rem;

  &.node-on {
    border-color: var(--c-cobalt);
    background: rgba(26, 58, 107, 0.08);
    color: var(--c-cobalt);
  }

  &.node-off {
    border-color: var(--c-sepia-light);
    background: var(--c-parchment);
    color: var(--c-sepia);
    text-decoration: line-through;
  }

  .node-check {
    font-size: 0.8rem;
    font-weight: bold;
  }
}

/* 偏移块 */
.offset-block {
  background: var(--c-cream);
  border: 1.5px solid var(--c-sepia-light);
  padding: 8px 10px;

  &.newline-alert {
    border-color: var(--c-crimson);
    background: rgba(139, 26, 26, 0.05);
  }

  .offset-top {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 6px;

    .offset-label {
      font-family: var(--font-body);
      font-size: 0.75rem;
      color: var(--c-sepia);
    }

    .offset-value {
      font-family: var(--font-headline);
      font-size: 1.5rem;
      font-weight: bold;
      color: var(--c-crimson);
    }

    .newline-badge {
      font-family: var(--font-body);
      font-size: 0.72rem;
      background: var(--c-crimson);
      color: var(--c-parchment);
      padding: 2px 6px;
    }
  }

  .offset-track {
    height: 8px;
    background: var(--c-sepia-light);
    border: 1px solid var(--c-sepia);
    position: relative;
    overflow: hidden;
    margin-bottom: 5px;

    .offset-fill {
      position: absolute;
      left: 0;
      top: 0;
      bottom: 0;
      background: var(--c-crimson);
      transition: width 0.3s ease;
    }
  }

  .offset-sources {
    display: flex;
    align-items: center;
    flex-wrap: wrap;
    gap: 4px;
    font-family: var(--font-body);
    font-size: 0.72rem;

    .sources-label {
      color: var(--c-sepia);
    }
    .source-tag {
      background: var(--c-parchment);
      border: 1px solid var(--c-sepia-light);
      padding: 1px 4px;
      color: var(--c-ink);
    }
  }
}

/* 锚点压力 */
.anchor-block {
  background: var(--c-cream);
  border: 1px solid var(--c-sepia-light);
  padding: 7px 10px;
}

/* 已改写节点 */
.rewritten-list {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.rewritten-item {
  font-family: var(--font-body);
  font-size: 0.75rem;
  background: var(--c-cream);
  border-left: 3px solid var(--c-cobalt);
  padding: 4px 8px;
  line-height: 1.4;

  .rewritten-node {
    font-weight: bold;
    color: var(--c-cobalt);
    margin-right: 4px;
  }
  .rewritten-desc {
    color: var(--c-sepia);
  }
}

/* 预警 */
.warning-list {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.warning-item {
  font-family: var(--font-body);
  font-size: 0.75rem;
  background: rgba(212, 160, 23, 0.1);
  border-left: 3px solid var(--c-status-active);
  padding: 4px 8px;
  color: var(--c-ink);

  i {
    color: var(--c-status-active);
    margin-right: 4px;
  }
}
