
.macro-layout {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.section-head {
  font-family: var(--font-headline);
  font-size: 0.85rem;
  font-weight: bold;
  border-bottom: 2px solid var(--c-ink);
  padding-bottom: 2px;
  margin-bottom: 6px;
  letter-spacing: 0.05em;
}

.gauge-group {
  background: var(--c-cream);
  border: 1px solid var(--c-sepia-light);
  padding: 7px 9px;
  margin-bottom: 6px;

  .gauge-group-label {
    font-family: var(--font-body);
    font-size: 0.68rem;
    color: var(--c-sepia);
    letter-spacing: 0.12em;
    margin-bottom: 5px;
  }
}

.recent-affairs {
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.affair-item {
  font-family: var(--font-body);
  font-size: 0.78rem;
  line-height: 1.4;
  background: var(--c-cream);
  border-left: 3px solid var(--c-sepia);
  padding: 4px 8px;

  .affair-name {
    font-weight: bold;
    color: var(--c-ink);
    margin-right: 4px;
  }

  .affair-desc {
    color: var(--c-sepia);
  }
}
