
.player-layout {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.section-head {
  font-family: var(--font-headline);
  font-size: 0.85rem;
  font-weight: bold;
  border-bottom: 2px solid var(--c-ink);
  padding-bottom: 2px;
  margin-bottom: 6px;
  letter-spacing: 0.05em;
}

.identity-card,
.info-card,
.status-card,
.action-card {
  background: var(--c-cream);
  border: 1.5px solid var(--c-sepia-light);
  padding: 8px 10px;
}

.identity-row {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
}

.identity-field {
  display: flex;
  gap: 5px;
  align-items: baseline;
  font-family: var(--font-body);

  .id-label {
    font-size: 0.7rem;
    color: var(--c-sepia);
    background: var(--c-parchment);
    border: 1px solid var(--c-sepia-light);
    padding: 1px 4px;
  }

  .id-value {
    font-size: 0.8rem;
    color: var(--c-ink);
    font-weight: bold;
  }
}

.info-row {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 4px;
  font-family: var(--font-body);
  font-size: 0.75rem;
  margin-bottom: 4px;

  .info-label {
    color: var(--c-sepia);
  }
  .info-value {
    color: var(--c-ink);
  }
}

.source-tag {
  font-size: 0.7rem;
  background: var(--c-parchment);
  border: 1px solid var(--c-sepia-light);
  padding: 1px 5px;
  color: var(--c-ink);
}

.action-num {
  display: flex;
  justify-content: space-between;
  font-family: var(--font-body);
  font-size: 0.75rem;
  padding: 3px 0;
  border-bottom: 1px dashed var(--c-sepia-light);
  margin-bottom: 6px;

  .num-label {
    color: var(--c-sepia);
  }
  .num-value {
    font-weight: bold;
    color: var(--c-ink);
  }
}

.resource-title {
  font-family: var(--font-body);
  font-size: 0.7rem;
  color: var(--c-sepia);
  letter-spacing: 0.06em;
  margin: 7px 0 4px;
}

.resource-list {
  display: flex;
  flex-direction: column;
  gap: 3px;
}

.resource-item {
  display: flex;
  gap: 5px;
  font-family: var(--font-body);
  font-size: 0.73rem;

  .resource-name {
    font-weight: bold;
    color: var(--c-ink);
    background: var(--c-parchment);
    border: 1px solid var(--c-sepia-light);
    padding: 0 4px;
  }

  .resource-desc {
    color: var(--c-sepia);
  }
}

.network-list {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
}

.network-tag {
  font-family: var(--font-body);
  font-size: 0.72rem;
  background: var(--c-cobalt);
  color: var(--c-parchment);
  padding: 2px 6px;
}
