
.faction-layout {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.faction-card {
  border: 1.5px solid var(--c-sepia-light);
  background: var(--c-cream);
}

.faction-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 6px 10px;
  background: var(--c-ink);
  cursor: pointer;
  user-select: none;

  &:active {
    opacity: 0.85;
  }

  .faction-name {
    font-family: var(--font-headline);
    font-size: 0.85rem;
    font-weight: bold;
    color: var(--c-parchment);
    letter-spacing: 0.04em;
  }

  .faction-toggle {
    color: var(--c-sepia);
    font-size: 0.75rem;
  }
}

.faction-body {
  padding: 7px 10px;
}

.faction-str {
  display: flex;
  gap: 4px;
  font-family: var(--font-body);
  font-size: 0.73rem;
  margin-bottom: 3px;

  .str-key {
    color: var(--c-sepia);
  }
  .str-val {
    color: var(--c-ink);
  }
}

.faction-bool {
  display: flex;
  justify-content: space-between;
  font-family: var(--font-body);
  font-size: 0.73rem;
  margin-bottom: 3px;

  .bool-key {
    color: var(--c-ink);
  }
  .bool-true {
    color: var(--c-crimson);
    font-weight: bold;
  }
  .bool-false {
    color: var(--c-sepia);
  }
}
