
.card {
  width: 100%;
  max-width: 720px;
  background-color: var(--c-parchment);
  border: 2.5px solid var(--c-ink);
  box-shadow: 6px 6px 0 rgba(26, 18, 9, 0.15);
  display: flex;
  flex-direction: column;
  font-family: var(--font-body);
  color: var(--c-ink);
  font-size: 13px;
  line-height: 1.4;
  margin: 0 auto;
}

.tab-nav {
  display: flex;
  background: var(--c-ink);
  border-top: 1px solid rgba(158, 136, 102, 0.4);
}

.tab-btn {
  flex: 1;
  padding: 7px 4px;
  border: none;
  border-right: 1px solid rgba(158, 136, 102, 0.3);
  background: transparent;
  color: var(--c-sepia);
  font-size: 0.8rem;
  font-family: var(--font-headline);
  font-weight: bold;
  cursor: pointer;
  transition: all 0.15s;
  letter-spacing: 0.02em;

  &:last-child {
    border-right: none;
  }

  &:hover {
    background: rgba(158, 136, 102, 0.2);
    color: var(--c-parchment);
  }

  &.active {
    background: var(--c-parchment);
    color: var(--c-ink);
    position: relative;
  }
}

.content-area {
  padding: 12px;
  background: var(--c-parchment);
  min-height: 0;
}

.tab-pane {
  animation: fadeIn 0.3s ease;
}

@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(4px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}
