
.header-card {
  background: var(--c-ink);
  color: var(--c-parchment);
  font-family: var(--font-headline);
}

.tricolor-bar {
  display: flex;
  height: 5px;

  .tc-r {
    flex: 1;
    background: var(--c-tricolor-r);
  }
  .tc-w {
    flex: 1;
    background: var(--c-tricolor-w);
  }
  .tc-b {
    flex: 1;
    background: var(--c-tricolor-b);
  }
}

.header-main {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 12px 4px;
  border-bottom: 1px solid var(--c-sepia);

  .revolution-stage {
    font-size: 1rem;
    font-weight: bold;
    letter-spacing: 0.04em;
    color: var(--c-parchment);
  }

  .time-block {
    display: flex;
    align-items: center;
    gap: 5px;
    font-family: var(--font-body);
    font-size: 0.78rem;
    color: var(--c-sepia);

    .time-label {
      background: var(--c-sepia);
      color: var(--c-ink);
      padding: 1px 3px;
      font-size: 0.68rem;
    }

    .time-value {
      color: var(--c-parchment);
    }

    .date-phase {
      font-size: 0.7rem;
      color: var(--c-sepia);
    }
  }
}

.weather-row {
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 4px 12px;
  font-family: var(--font-body);
  font-size: 0.75rem;
  color: var(--c-sepia);
  border-bottom: 1px solid rgba(158, 136, 102, 0.3);

  .weather-sep {
    color: rgba(158, 136, 102, 0.5);
  }

  .weather-item {
    white-space: nowrap;
  }
}

.focus-block {
  padding: 6px 12px 8px;
  font-family: var(--font-body);

  .focus-title {
    font-size: 0.68rem;
    color: var(--c-sepia);
    text-align: center;
    letter-spacing: 0.1em;
    margin-bottom: 4px;
  }

  .focus-item {
    font-size: 0.8rem;
    color: var(--c-parchment);
    line-height: 1.4;
    padding: 1px 0;
  }

  .focus-bullet {
    color: var(--c-crimson);
    font-size: 0.6rem;
    margin-right: 3px;
  }
}
