
.city-layout {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.section-head {
  font-family: var(--font-headline);
  font-size: 0.85rem;
  font-weight: bold;
  border-bottom: 2px solid var(--c-ink);
  padding-bottom: 2px;
  margin-bottom: 6px;
  letter-spacing: 0.05em;
}

.overview-card {
  background: var(--c-cream);
  border: 1px solid var(--c-sepia-light);
  padding: 8px 10px;
}

.tag-row {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-bottom: 7px;

  .tag-item {
    font-family: var(--font-body);
    font-size: 0.73rem;
    background: var(--c-parchment);
    border: 1px solid var(--c-sepia-light);
    padding: 2px 6px;
    color: var(--c-ink);
  }
}

.locations-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
  gap: 7px;
}

.location-card {
  background: var(--c-cream);
  border: 1.5px solid var(--c-sepia-light);
  padding: 7px 8px;

  .location-name {
    font-family: var(--font-headline);
    font-size: 0.82rem;
    font-weight: bold;
    border-bottom: 1px solid var(--c-sepia-light);
    padding-bottom: 3px;
    margin-bottom: 4px;
  }

  .location-ctrl {
    font-family: var(--font-body);
    font-size: 0.7rem;
    color: var(--c-sepia);
    margin-bottom: 5px;
  }
}

.location-bool {
  display: flex;
  justify-content: space-between;
  font-family: var(--font-body);
  font-size: 0.72rem;
  margin-bottom: 2px;

  .bool-key {
    color: var(--c-ink);
  }
  .bool-true {
    color: var(--c-crimson);
    font-weight: bold;
  }
  .bool-false {
    color: var(--c-sepia);
  }
}

.location-str,
.district-str {
  display: flex;
  gap: 4px;
  font-family: var(--font-body);
  font-size: 0.72rem;
  margin-bottom: 2px;

  .str-key {
    color: var(--c-sepia);
  }
  .str-val {
    color: var(--c-ink);
  }
}

.districts-list {
  display: flex;
  flex-direction: column;
  gap: 7px;
}

.district-card {
  background: var(--c-cream);
  border: 1.5px solid var(--c-sepia-light);
  padding: 7px 10px;

  .district-name {
    font-family: var(--font-headline);
    font-size: 0.82rem;
    font-weight: bold;
    border-bottom: 1px solid var(--c-sepia-light);
    padding-bottom: 3px;
    margin-bottom: 5px;
  }
}

.slogan-row {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 4px;
  margin-top: 4px;
  font-family: var(--font-body);

  .slogan-label {
    font-size: 0.7rem;
    color: var(--c-sepia);
  }

  .slogan-tag {
    font-size: 0.7rem;
    background: var(--c-crimson);
    color: var(--c-parchment);
    padding: 1px 5px;
  }
}
